import { today } from "@/features/today/api/today-data";
import { AIStrip } from "@/components/shared/AIStrip";
import { BridgePrimaryButton } from "@/features/bridge/components/BridgePrimaryButton";
import "./today.css";

export default function TodayPage() {
  const { hero, aiStrip, telemetry, gauges, cash, channels } = today;
  const maxK = Math.max(...hero.bars.map((b) => b.valueK));

  return (
    <div className="today-room">
      {/* ===== TOP BAR ===== */}
      <div className="room-topbar">
        <h1 className="today-greet">{today.greeting}</h1>
        <div className="top-actions">
          <div className="today-meta">
            <div className="today-meta-day">{today.metaDay}</div>
            <div className="today-meta-time">{today.metaTime}</div>
          </div>
          <button className="btn-util">
            The Study <span className="count">{today.studyCount}</span>
          </button>
          <BridgePrimaryButton dept="ops">
            The Bridge <span className="count">{today.bridgeCount}</span>
          </BridgePrimaryButton>
        </div>
      </div>

      <div className="today-wrap">
        {/* ===== AI STRIP ===== */}
        <AIStrip
          label={aiStrip.label}
          meta={{ confidence: aiStrip.confidence, sources: aiStrip.sources, syncedAgo: aiStrip.syncedAgo }}
          cards={aiStrip.cards.map((c) => ({ ...c, accent: `var(--d-${c.accent})` }))}
        />

        {/* ===== HERO + TELEMETRY ===== */}
        <div className="today-grid">
          <section className="hero-card">
            <div className="hero-card-head">
              <div>
                <div className="cap">Today so far</div>
                <div className="hero-revenue">{hero.todayRevenue}</div>
                <div className="hero-meta">
                  {hero.todayMeta} · <span className="up">{hero.todayVsYesterday}</span> vs yesterday this time
                </div>
              </div>
              <div style={{ textAlign: "right" }}>
                <div className="cap">Yesterday&apos;s close</div>
                <div
                  style={{
                    fontFamily: "var(--font-display)",
                    fontSize: 24,
                    fontWeight: 300,
                    letterSpacing: "-0.015em",
                    marginTop: 4,
                  }}
                >
                  {hero.yesterdayClose}
                </div>
                <div
                  className="hero-meta"
                  style={{
                    color: "var(--d-finance)",
                    fontWeight: 500,
                    fontFamily: "var(--font-mono)",
                    fontSize: 11,
                  }}
                >
                  {hero.yesterdayMeta}
                </div>
              </div>
            </div>

            <div className="hero-bars-head">
              <div className="hero-bars-kicker">Daily revenue · $K</div>
            </div>
            <div className="hero-bars">
              {hero.bars.map((bar, i) => {
                const heightPct = (bar.valueK / maxK) * 100;
                const variant = bar.variant ?? "";
                return (
                  <div key={i} className={`hero-bar-col ${variant}`}>
                    <span className="hero-bar-val">{bar.valueK}</span>
                    <div className="hero-bar" style={{ height: `${heightPct}%` }} />
                  </div>
                );
              })}
            </div>
            <div className="hero-bars-axis">
              <span>May 2</span>
              <span>May 8</span>
              <span>May 14</span>
              <span>Today</span>
            </div>

            <div className="hero-progress">
              <div className="hero-progress-left">
                <div className="hero-progress-kicker">{hero.monthLabel}</div>
                <div className="hero-progress-readout">
                  <span>{hero.monthRevenue}</span>
                </div>
              </div>
              <div className="hero-progress-right">
                <div className="hero-progress-kicker">{hero.projectedLabel}</div>
                <div className="hero-progress-readout">
                  <span>{hero.projectedRevenue}</span>
                  <span className="yoy-delta">{hero.projectedDelta}</span>
                </div>
                <div className="hero-progress-projection-note">{hero.projectedNote}</div>
              </div>
            </div>
            <div className="hero-progress-bar">
              <div className="hero-progress-fill" style={{ width: `${hero.fillPct}%` }}>
                <span className="hero-progress-value">{hero.fillLabel}</span>
              </div>
              <div className="hero-progress-tick" style={{ left: `${hero.fillPct}%` }}>
                <span className="hero-progress-tick-label">{hero.tickLabel}</span>
              </div>
            </div>
            <div className="hero-progress-status">{hero.statusLine}</div>
          </section>

          <section className="telemetry-card">
            <div className="telemetry-card-head">
              <div className="cap">Telemetry · Live</div>
              <div className="dot-pulse" />
            </div>
            <div className="telemetry-rows">
              {telemetry.map((row, i) => (
                <div key={i} className="telemetry-row">
                  <div className="lbl">{row.label}</div>
                  <div className="val">{row.value}</div>
                  <div className={`delta ${row.deltaState === "up" ? "up" : row.deltaState === "down" ? "down" : ""}`}>
                    {row.delta}
                  </div>
                </div>
              ))}
            </div>
          </section>
        </div>

        {/* ===== DEPARTMENT DOORWAYS ===== */}
        <div className="gauges">
          {gauges.map((g, i) => (
            <div key={i} className="gauge" data-d={g.dept}>
              <div className="gauge-head">
                <span>{g.label}</span>
                <span>{g.metric}</span>
              </div>
              <div className="gauge-value">{g.value}</div>
              <div className="gauge-meta">{g.meta}</div>
              <div className="gauge-delta">{g.delta}</div>
            </div>
          ))}
        </div>

        {/* ===== LOWER GRID: CASH + CHANNELS ===== */}
        <div className="lower-grid">
          <section className="cash-card">
            <div className="cash-head">
              <div className="cap">Cash position</div>
              <div className="cash-status">{cash.status}</div>
            </div>
            <div className="cash-gauge-layout">
              <svg className="cash-gauge-svg" viewBox="0 0 220 150" aria-hidden>
                <path className="cash-arc-base" d="M 22 124 A 88 88 0 0 1 198 124" />
                <path className="cash-arc-alert" d="M 22 124 A 88 88 0 0 1 66 49" />
                <path className="cash-arc-target" d="M 66 49 A 88 88 0 0 1 198 124" />
                <line className="cash-needle" x1="110" y1="124" x2="76.9" y2="58.9" />
                <circle className="cash-pivot" cx="110" cy="124" r="6" />
                <text className="cash-tick-label" x="22" y="142" textAnchor="middle">0</text>
                <text className="cash-tick-label major" x="110" y="32" textAnchor="middle">6 mo</text>
                <text className="cash-tick-label" x="198" y="142" textAnchor="middle">12+</text>
                <text className="cash-tick-label" x="55" y="46" textAnchor="end">3</text>
                <text className="cash-tick-label" x="165" y="46" textAnchor="start">9</text>
              </svg>
              <div>
                <div className="cash-readout-value">
                  {cash.months}
                  <span className="unit"> mo</span>
                </div>
                <div className="cash-readout-sub">{cash.monthsDelta}</div>
                <div className="cash-readout-grid">
                  <div className="cash-readout-cell">
                    <div className="lbl">Cash on hand</div>
                    <div className="val">{cash.onHand}</div>
                  </div>
                  <div className="cash-readout-cell">
                    <div className="lbl">Burn / mo</div>
                    <div className="val">{cash.burn}</div>
                  </div>
                  <div className="cash-readout-cell">
                    <div className="lbl">Inventory</div>
                    <div className="val">{cash.inventory}</div>
                  </div>
                  <div className="cash-readout-cell">
                    <div className="lbl">Receivable</div>
                    <div className="val">{cash.receivable}</div>
                  </div>
                </div>
              </div>
            </div>

            <div className="cash-trend">
              <div className="cash-trend-head">
                <div className="cash-trend-kicker">Cash trend · 12 months</div>
                <div className="cash-trend-verdict">Improving</div>
              </div>
              <div className="cash-trend-sparkline">
                <svg viewBox="0 0 300 54" preserveAspectRatio="none" aria-hidden>
                  <line x1="0" y1="32" x2="300" y2="32" stroke="rgba(0,0,0,0.06)" strokeWidth="0.5" strokeDasharray="2 3" />
                  <path
                    d="M 0 44 L 25 42 L 50 46 L 75 38 L 100 36 L 125 32 L 150 30 L 175 28 L 200 24 L 225 20 L 250 18 L 275 16 L 300 12 L 300 54 L 0 54 Z"
                    fill="rgba(29,158,117,0.10)"
                  />
                  <path
                    d="M 0 44 L 25 42 L 50 46 L 75 38 L 100 36 L 125 32 L 150 30 L 175 28 L 200 24 L 225 20 L 250 18 L 275 16 L 300 12"
                    stroke="var(--d-finance)"
                    strokeWidth="1.5"
                    fill="none"
                    strokeLinecap="round"
                    strokeLinejoin="round"
                  />
                  <circle cx="300" cy="12" r="3.5" fill="var(--d-finance)" />
                  <circle cx="300" cy="12" r="7" fill="rgba(29,158,117,0.18)" />
                  <circle cx="50" cy="46" r="2" fill="var(--ink-3)" />
                </svg>
              </div>
              <div className="cash-trend-foot">
                <div className="cash-trend-endpoint">
                  <div className="lbl">{cash.trough.label}</div>
                  <div className="val">{cash.trough.value}</div>
                </div>
                <div className="cash-trend-endpoint right">
                  <div className="lbl">{cash.now.label}</div>
                  <div className="val">{cash.now.value}</div>
                </div>
              </div>
            </div>
          </section>

          <section className="channels-card">
            <div className="channels-head">
              <div className="cap">Channel performance</div>
              <div className="channels-toggle">
                <button className="active">Today</button>
                <button>7 days</button>
                <button>30 days</button>
              </div>
            </div>
            <div className="channel-row head">
              <span>Channel</span>
              <span>Share of revenue</span>
              <span className="num">Orders</span>
              <span className="num">Revenue</span>
              <span className="num">Spend</span>
              <span className="num">ROAS</span>
            </div>
            {channels.map((c) => (
              <div key={c.id} className="channel-row">
                <span className="name">
                  <span className="dot" style={{ background: c.dotColor }} />
                  <span>{c.label}</span>
                </span>
                <div className="bar-track">
                  <div className="bar-fill" style={{ width: `${c.sharePct}%`, background: c.barColor }} />
                </div>
                <span className="num orders">{c.orders}</span>
                <span className="num rev">{c.revenue}</span>
                <span className={`num spend ${c.spend ? "" : "dim"}`}>{c.spend ?? "—"}</span>
                <span className={`num roas ${c.roasState === "high" ? "high" : c.roasState === "low" ? "low" : ""}`}>
                  {c.roas !== null ? `${c.roas}×` : "∞"}
                </span>
              </div>
            ))}
          </section>
        </div>
      </div>
    </div>
  );
}
