/**
 * Mock data for the Today page. Shape loosely matches what a real API would
 * return (arrays-with-dates for time series, not flat single values) so swap
 * to a real source is changing this file, not every component.
 */

export type AICardAccent = "ops" | "finance" | "growth" | "customers";

export type AICard = {
  tag: string;
  title: string;
  body: string;
  accent: AICardAccent;
};

export type DailyBar = {
  /** ISO date string */
  date: string;
  /** Revenue in thousands of currency units (display) */
  valueK: number;
  /** Render this column with the special "today" or "yesterday" treatment */
  variant?: "today" | "yesterday";
};

export type ChannelRow = {
  id: string;
  label: string;
  dotColor: string;
  /** Share of revenue 0–100 */
  sharePct: number;
  /** Color for the bar fill */
  barColor: string;
  orders: number;
  revenue: string;
  spend: string | null;
  /** ROAS multiplier, or null for "∞" (organic/referral) */
  roas: number | null;
  roasState: "high" | "low" | "neutral";
};

export type Gauge = {
  dept: AICardAccent;
  label: string;
  metric: string;
  value: string;
  meta: string;
  delta: string;
};

export type TelemetryRow = {
  label: string;
  value: string;
  delta: string;
  deltaState: "up" | "down" | "neutral";
};

